class BasicQueue:
    def __init__(self):
        self.items = []
        self.index = 0

    def enqueue(self, item):
        # Add an item to the end of the queue
        self.items.append(item)

        # If the queue is not empty, increment index to point to the next item
        if not self.is_empty():
            self.index += 1

    def dequeue(self):
        # Check if the queue is empty
        if not self.is_empty():
            # Remove the last item
            item = self.items[0]
            del self.items[0]  # free memory for this item
            # Return the removed item
            return item

    def is_empty(self):
        # Check if the queue is empty
        return len(self.items) == 0

    def size(self):
        # Get the number of items in the queue
        return len(self.items)
