def get_dict_value_path(d: Dict[str, Dict[str, int]], path: list) -> any:
    """
    Retrieves a value from a nested dictionary based on a given path.

    Parameters:
        d (Dict[str, Dict[str, int]]): The outer dictionary containing nested dictionaries.
        path (list): A list of keys representing the depth of the nested dictionary.

    Returns:
        Any: The value associated with the final key in the path, or None if the path contains an invalid or missing key.
    """
    # Base case for an empty dictionary or path
    if not d or len(path) == 0:
        return None

    # Helper function to recursively search within sub-dictionaries
    def search_dict(key: str):
        nonlocal d, path
        for item in d[key]:
            child_key = item
            # Recursively search within nested sub-dictionaries
            result = search_dict(child_key)
            if isinstance(result, dict):
                # If the result is also a dictionary, it's a valid path
                if isinstance(result, dict):
                    # Ensure both items exist before combining them
                    if isinstance(item, dict):
                        # Merge dictionaries and continue searching
                        yield from (result + item)
                    else:
                        # Return the first existing dictionary if there's one after the current item
                        yield from (item)
                else:
                    # Continue to handle another key-value pair
                    pass
            else:
                # If the key already exists, skip over this level
                break
        return result

    # Start the search from the root key of the outer dictionary
    for key in path:
        result = search_dict(key)
        if isinstance(result, dict):
            break  # Move to the next level after finding the last key
        else:
            return None  # Return None if no valid path was found

